package com.blissless.tensei.streamimport android.app.Applicationimport android.content.Intentimport android.util.Logimport androidx.lifecycle.AndroidViewModelimport androidx.lifecycle.viewModelScopeimport eu.kanade.tachiyomi.animesource.AnimeCatalogueSourceimport eu.kanade.tachiyomi.animesource.model.Hosterimport eu.kanade.tachiyomi.animesource.model.SAnimeimport eu.kanade.tachiyomi.animesource.model.SEpisodeimport eu.kanade.tachiyomi.animesource.model.Videoimport eu.kanade.tachiyomi.animesource.online.AnimeHttpSourceimport com.blissless.tensei.stream.SourceManager.SourceWithExtimport kotlinx.coroutines.Dispatchersimport kotlinx.coroutines.flow.MutableStateFlowimport kotlinx.coroutines.flow.StateFlowimport kotlinx.coroutines.flow.asStateFlowimport kotlinx.coroutines.launchimport kotlinx.coroutines.withContextdata class SearchResult(    val source: SourceWithExt,    val anime: SAnime,)data class StreamUiState(    val isInitialized: Boolean = false,    val isSearching: Boolean = false,    val query: String = "",    val searchResults: List<SearchResult> = emptyList(),    val selectedAnime: SAnime? = null,    val selectedSource: SourceWithExt? = null,    val episodes: List<SEpisode> = emptyList(),    val isLoadingEpisodes: Boolean = false,    val selectedEpisode: SEpisode? = null,    val isLoadingVideos: Boolean = false,    val hosters: List<Hoster>? = null,    val selectedHoster: Hoster? = null,    val pendingVideos: List<Video>? = null,    val error: String? = null,)class StreamViewModel(application: Application) : AndroidViewModel(application) {    val manager = SourceManager(application)    private val _uiState = MutableStateFlow(StreamUiState())    val uiState: StateFlow<StreamUiState> = _uiState.asStateFlow()    fun reloadSources() {        _uiState.value = _uiState.value.copy(isInitialized = false)        viewModelScope.launch {            manager.reloadSources()            manager.loadSources()            _uiState.value = _uiState.value.copy(isInitialized = true)        }    }    fun loadSources() {        if (_uiState.value.isInitialized) return        viewModelScope.launch {            manager.loadSources()            _uiState.value = _uiState.value.copy(isInitialized = true)        }    }    fun search(query: String, sourceFilter: SourceWithExt? = null) {        if (query.isBlank()) return        _uiState.value = _uiState.value.copy(            isSearching = true,            query = query,            searchResults = emptyList(),            selectedAnime = null,            selectedSource = null,            episodes = emptyList(),            selectedEpisode = null,        )        viewModelScope.launch {            val results = mutableListOf<SearchResult>()            manager.search(query, sourceFilter) { sw, animes ->                animes.forEach { anime ->                    results.add(SearchResult(sw, anime))                }                _uiState.value = _uiState.value.copy(searchResults = results.toList())            }            Log.i("ExtensionSearch", "Total search results for \"$query\": ${results.size}")            withContext(Dispatchers.Main) {                _uiState.value = _uiState.value.copy(isSearching = false, searchResults = results.toList())            }        }    }    fun selectAnime(source: SourceWithExt, anime: SAnime) {        _uiState.value = _uiState.value.copy(            selectedAnime = anime,            selectedSource = source,            isLoadingEpisodes = true,            episodes = emptyList(),            selectedEpisode = null,        )        viewModelScope.launch {            val episodes = manager.getEpisodes(source.source, anime)            _uiState.value = _uiState.value.copy(                episodes = episodes,                isLoadingEpisodes = false,            )        }    }    fun selectEpisode(episode: SEpisode) {        val state = _uiState.value        val source = state.selectedSource ?: return        val anime = state.selectedAnime        if (state.isLoadingVideos) return        _uiState.value = state.copy(            selectedEpisode = episode,            isLoadingVideos = true,            hosters = null,            selectedHoster = null,        )        viewModelScope.launch {            val hosters = manager.getHosters(source.source, episode, anime)            _uiState.value = _uiState.value.copy(                isLoadingVideos = false,                hosters = hosters,            )            when {                hosters.isNullOrEmpty() -> {                    loadAndPlay(source.source, episode = episode, anime = anime)                }                else -> {                    loadAndPlay(source.source, hosters.first(), episode, anime)                }            }        }    }    fun selectHoster(hoster: Hoster) {        val state = _uiState.value        val source = state.selectedSource ?: return        val episode = state.selectedEpisode ?: return        viewModelScope.launch {            _uiState.value = _uiState.value.copy(                selectedHoster = hoster,                isLoadingVideos = true,            )            loadAndPlay(source.source, hoster, episode, state.selectedAnime)        }    }    private suspend fun loadAndPlay(source: AnimeCatalogueSource, hoster: Hoster? = null, episode: SEpisode, anime: SAnime? = null) {        val videos = if (hoster != null) {            try {                val v = manager.getVideosFromHoster(source, hoster)                if (source is AnimeHttpSource) {                    PlayerData.extensionClient = source.client                }                v            } catch (e: Throwable) {                fallbackGetVideos(source, episode, anime, e.message)            }        } else {            fallbackGetVideos(source, episode, anime)        }        _uiState.value = _uiState.value.copy(isLoadingVideos = false)        launchPlayerWithVideos(videos)    }    private suspend fun fallbackGetVideos(        source: AnimeCatalogueSource, episode: SEpisode, anime: SAnime?, previousError: String? = null    ): List<Video> {        return try {            val v = manager.getVideosDirect(source, episode, anime)            if (source is AnimeHttpSource) {                PlayerData.extensionClient = source.client            }            v        } catch (e2: Throwable) {            val msg = previousError?.let { "$it; " } ?: ""            _uiState.value = _uiState.value.copy(error = "Failed to load videos: ${msg}${e2.message}")            emptyList()        }    }    private fun launchPlayerWithVideos(videos: List<Video>) {        if (videos.isEmpty()) {            return        }        _uiState.value = _uiState.value.copy(pendingVideos = videos)    }    fun selectVideo(index: Int) {        val state = _uiState.value        val oldVideos = state.pendingVideos ?: return        val source = state.selectedSource ?: return        val episode = state.selectedEpisode ?: return        val anime = state.selectedAnime        viewModelScope.launch {            _uiState.value = _uiState.value.copy(isLoadingVideos = true)            try {                val freshVideos = manager.getVideosDirect(source.source, episode, anime)                if (freshVideos.isNotEmpty()) {                    val freshVideo = freshVideos.getOrNull(index) ?: freshVideos.first()                    val ctx = getApplication<Application>()                    PlayerData.videos = freshVideos                    PlayerData.animeTitle = source.extension.name.removePrefix("Aniyomi: ")                    PlayerData.currentQualityIndex = freshVideos.indexOf(freshVideo).coerceAtLeast(0)                    PlayerData.selectedSubtitle = freshVideo.subtitleTracks.firstOrNull()                    PlayerData.selectedAudio = freshVideo.audioTracks.firstOrNull()                    PlayerData.extensionClient = (source.source as? AnimeHttpSource)?.client                    ctx.startActivity(Intent(ctx, PlayerActivity::class.java).apply {                        flags = Intent.FLAG_ACTIVITY_NEW_TASK                    })                } else {                    _uiState.value = _uiState.value.copy(error = "No videos available for this episode")                }            } catch (e: Throwable) {                val ctx = getApplication<Application>()                val fallbackVideo = oldVideos.getOrNull(index) ?: oldVideos.firstOrNull() ?: return@launch                PlayerData.videos = oldVideos                PlayerData.animeTitle = source.extension.name.removePrefix("Aniyomi: ")                PlayerData.currentQualityIndex = oldVideos.indexOf(fallbackVideo).coerceAtLeast(0)                PlayerData.selectedSubtitle = fallbackVideo.subtitleTracks.firstOrNull()                PlayerData.selectedAudio = fallbackVideo.audioTracks.firstOrNull()                PlayerData.extensionClient = (source.source as? AnimeHttpSource)?.client                ctx.startActivity(Intent(ctx, PlayerActivity::class.java).apply {                    flags = Intent.FLAG_ACTIVITY_NEW_TASK                })            } finally {                _uiState.value = _uiState.value.copy(pendingVideos = null, isLoadingVideos = false)            }        }    }    fun backToResults() {        _uiState.value = _uiState.value.copy(            selectedAnime = null,            selectedSource = null,            episodes = emptyList(),            selectedEpisode = null,            isLoadingEpisodes = false,            isLoadingVideos = false,            hosters = null,            selectedHoster = null,            pendingVideos = null,        )    }    fun clearError() {        _uiState.value = _uiState.value.copy(error = null)    }    fun getSources(): List<SourceWithExt> = manager.getSources()}